"use client"

import { useState, useEffect, useCallback } from 'react'
import { HttpTypes } from '@medusajs/types'
import Link from 'next/link'
import Image from 'next/image'
import { formatAmount } from '@/lib/helpers/money'
import { cn } from '@/lib/utils'
import { VerificationStatus } from './VerificationStatus'
import { SellerTrustLevel } from '@/components/common/TrustBadge'
import { customerBackendAPI } from '@/lib/api/customer-backend'
import {
  getSellerDashboard,
  getSellerListings,
  getSellerOrders,
  updateSellerListing,
  deleteSellerListing,
  type SellerDashboardStats,
  type SellerListing,
  type SellerOrder,
} from '@/lib/data/seller-dashboard'
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"

interface ConsumerSellerDashboardProps {
  customer: HttpTypes.StoreCustomer
}

type Tab = 'overview' | 'listings' | 'sales' | 'profile'

interface TierProgress {
  current_tier: string
  current_score: number
  next_tier: string | null
  next_tier_threshold: number | null
  progress_percentage: number
}

interface TrustData {
  trust_score: number
  seller_tier: string
  overall_rating: number
  total_reviews: number
  verification_status: string
  verification_badges: string[]
  seller_level: string
  months_active: number
  tier_progress: TierProgress
  recent_reviews: Array<{
    id: string
    rating: number
    comment: string
    created_at: string
  }>
}

const TIER_COLORS: Record<string, { bg: string; text: string; bar: string }> = {
  bronze: { bg: 'bg-orange-100 dark:bg-orange-900/20', text: 'text-orange-700 dark:text-orange-300', bar: 'bg-orange-500' },
  silver: { bg: 'bg-gray-100 dark:bg-gray-700/30', text: 'text-gray-700 dark:text-gray-300', bar: 'bg-gray-400' },
  gold: { bg: 'bg-yellow-100 dark:bg-yellow-900/20', text: 'text-yellow-700 dark:text-yellow-300', bar: 'bg-yellow-500' },
  platinum: { bg: 'bg-cyan-100 dark:bg-cyan-900/20', text: 'text-cyan-700 dark:text-cyan-300', bar: 'bg-cyan-500' },
  diamond: { bg: 'bg-purple-100 dark:bg-purple-900/20', text: 'text-purple-700 dark:text-purple-300', bar: 'bg-purple-500' },
}

function mapTierToTrustLevel(tier: string): SellerTrustLevel['level'] {
  switch (tier.toLowerCase()) {
    case 'bronze': return 'basic'
    case 'silver': return 'verified'
    case 'gold': return 'premium'
    case 'platinum':
    case 'diamond': return 'pro'
    default: return 'unverified'
  }
}

function getListingStatusColor(status: string) {
  switch (status) {
    case 'published':
      return 'text-green-600 bg-green-100 dark:text-green-400 dark:bg-green-900/20'
    case 'draft':
      return 'text-yellow-600 bg-yellow-100 dark:text-yellow-400 dark:bg-yellow-900/20'
    default:
      return 'text-gray-600 bg-gray-100 dark:text-gray-400 dark:bg-gray-900/20'
  }
}

const PAGE_SIZE = 20

export function ConsumerSellerDashboard({ customer }: ConsumerSellerDashboardProps) {
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [activeTab, setActiveTab] = useState<Tab>('overview')

  // Commerce backend data
  const [dashboard, setDashboard] = useState<SellerDashboardStats | null>(null)
  const [listings, setListings] = useState<SellerListing[]>([])
  const [listingsTotal, setListingsTotal] = useState(0)
  const [listingsLoaded, setListingsLoaded] = useState(false)
  const [listingsLoading, setListingsLoading] = useState(false)
  const [orders, setOrders] = useState<SellerOrder[]>([])
  const [ordersTotal, setOrdersTotal] = useState(0)
  const [ordersLoaded, setOrdersLoaded] = useState(false)
  const [ordersLoading, setOrdersLoading] = useState(false)

  // Customer backend data (trust/tier)
  const [trustData, setTrustData] = useState<TrustData | null>(null)

  // Filters
  const [listingFilter, setListingFilter] = useState('all')
  const [listingOffset, setListingOffset] = useState(0)
  const [orderOffset, setOrderOffset] = useState(0)

  // Action states
  const [actionLoading, setActionLoading] = useState<string | null>(null)
  const [listingToDelete, setListingToDelete] = useState<SellerListing | null>(null)

  // --- Data Loading ---

  useEffect(() => {
    loadDashboard()
  }, [customer.id])

  const loadDashboard = async () => {
    try {
      setLoading(true)
      setError(null)

      const dashboardData = await getSellerDashboard()
      if (!dashboardData) {
        setError('Unable to load dashboard. Please try again.')
        return
      }
      setDashboard(dashboardData)
      setLoading(false)

      // Load trust data async — non-critical, don't block initial render
      customerBackendAPI.getSellerDashboardSummary(dashboardData.seller_id)
        .then(summary => {
          if (summary.success) {
            setTrustData(summary.data)
          }
        })
        .catch(() => {
          // Trust data is supplementary — dashboard works without it
        })
    } catch {
      setError('Unable to load dashboard. Please try again.')
      setLoading(false)
    }
  }

  const loadListings = useCallback(async (status = listingFilter, offset = 0) => {
    try {
      setListingsLoading(true)
      const result = await getSellerListings({ status, limit: PAGE_SIZE, offset })
      if (result) {
        setListings(result.listings)
        setListingsTotal(result.total)
        setListingsLoaded(true)
      }
    } catch {
      // Silently fail — user sees empty state
    } finally {
      setListingsLoading(false)
    }
  }, [listingFilter])

  const loadOrders = useCallback(async (offset = 0) => {
    try {
      setOrdersLoading(true)
      const result = await getSellerOrders({ limit: PAGE_SIZE, offset })
      if (result) {
        setOrders(result.orders)
        setOrdersTotal(result.total)
      }
      setOrdersLoaded(true)
    } catch {
      // Silently fail — user sees empty state
    } finally {
      setOrdersLoading(false)
    }
  }, [])

  // Lazy-load tab data
  useEffect(() => {
    if (activeTab === 'listings' && !listingsLoaded && !listingsLoading) {
      loadListings()
    }
    if (activeTab === 'sales' && !ordersLoaded && !ordersLoading) {
      loadOrders()
    }
  }, [activeTab, listingsLoaded, listingsLoading, ordersLoaded, ordersLoading, loadListings, loadOrders])

  // --- Listing Actions ---

  const handleToggleListing = async (listing: SellerListing) => {
    const newStatus = listing.status === 'published' ? 'draft' : 'published'
    setActionLoading(listing.id)
    const success = await updateSellerListing(listing.id, { status: newStatus })
    setActionLoading(null)
    if (success) {
      setListings(prev => prev.map(l =>
        l.id === listing.id ? { ...l, status: newStatus } : l
      ))
      // Refresh dashboard stats
      const updated = await getSellerDashboard()
      if (updated) setDashboard(updated)
    }
  }

  const handleDeleteListing = (listing: SellerListing) => {
    setListingToDelete(listing)
  }

  const handleDeleteConfirmed = async () => {
    if (!listingToDelete) return
    const listing = listingToDelete
    setListingToDelete(null)
    setActionLoading(listing.id)
    const success = await deleteSellerListing(listing.id)
    setActionLoading(null)
    if (success) {
      setListings(prev => prev.filter(l => l.id !== listing.id))
      setListingsTotal(prev => prev - 1)
      const updated = await getSellerDashboard()
      if (updated) setDashboard(updated)
    }
  }

  // --- Pagination ---

  const handleListingFilterChange = (status: string) => {
    setListingFilter(status)
    setListingOffset(0)
    setListingsLoaded(false)
    loadListings(status, 0)
  }

  const handleListingPage = (newOffset: number) => {
    setListingOffset(newOffset)
    loadListings(listingFilter, newOffset)
  }

  const handleOrderPage = (newOffset: number) => {
    setOrderOffset(newOffset)
    loadOrders(newOffset)
  }

  // --- Derived values ---

  const trustLevel: SellerTrustLevel = trustData ? {
    level: mapTierToTrustLevel(trustData.seller_tier),
    score: trustData.trust_score,
    reviewCount: trustData.total_reviews,
    isBusinessSeller: false,
    hasIdVerification: trustData.verification_badges.includes('identity'),
    hasAddressVerification: trustData.verification_badges.includes('address'),
    hasPaymentVerification: trustData.verification_badges.includes('payment'),
    accountAge: trustData.months_active,
    totalSales: dashboard?.total_sales ?? 0,
  } : {
    level: 'unverified' as const,
    score: 0,
    reviewCount: 0,
    isBusinessSeller: false,
    hasIdVerification: false,
    hasAddressVerification: false,
    hasPaymentVerification: false,
    accountAge: 0,
    totalSales: 0,
  }

  // --- Render ---

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="animate-pulse space-y-4">
          <div className="h-8 bg-gray-200 dark:bg-gray-700 rounded w-1/3" />
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            {[...Array(4)].map((_, i) => (
              <div key={i} className="h-24 bg-gray-200 dark:bg-gray-700 rounded-lg" />
            ))}
          </div>
          <div className="h-64 bg-gray-200 dark:bg-gray-700 rounded-lg" />
        </div>
      </div>
    )
  }

  if (error) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="bg-card rounded-lg border border-border p-8 text-center">
          <svg className="w-12 h-12 text-red-400 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4c-.77-.833-1.964-.833-2.732 0L4.082 16.5c-.77.833.192 2.5 1.732 2.5z" />
          </svg>
          <p className="text-secondary mb-4">{error}</p>
          <button
            onClick={loadDashboard}
            className="px-4 py-2 bg-action text-white rounded-lg hover:bg-action-hover transition-colors"
          >
            Try Again
          </button>
        </div>
      </div>
    )
  }

  if (!dashboard) return null

  return (
    <div className="container mx-auto px-4 py-8">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between mb-8">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <h1 className="text-2xl font-bold text-primary">
              Welcome back, {customer.first_name}!
            </h1>
            {trustData && (
              <TierBadge tier={trustData.seller_tier} />
            )}
          </div>
          <p className="text-secondary">
            Manage your card listings and track your sales performance
          </p>
        </div>
        <div className="mt-4 sm:mt-0">
          <Link
            href="/sell/list-card"
            className="inline-flex items-center gap-2 px-4 py-2 bg-action text-white rounded-lg hover:bg-action-hover transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
            List New Card
          </Link>
        </div>
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        <StatCard
          label="Active Listings"
          value={String(dashboard.active_listings)}
          iconBg="bg-green-100 dark:bg-green-900/20"
          iconColor="text-green-600 dark:text-green-400"
          icon={<path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" />}
        />
        <StatCard
          label="Total Sales"
          value={String(dashboard.total_sales)}
          iconBg="bg-blue-100 dark:bg-blue-900/20"
          iconColor="text-blue-600 dark:text-blue-400"
          icon={<path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />}
        />
        <StatCard
          label="This Month"
          value={formatAmount(dashboard.monthly_revenue / 100, 'USD')}
          iconBg="bg-yellow-100 dark:bg-yellow-900/20"
          iconColor="text-yellow-600 dark:text-yellow-400"
          icon={<path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />}
        />
        <RatingStatCard
          rating={trustData?.overall_rating ?? 0}
          reviewCount={trustData?.total_reviews ?? 0}
        />
      </div>

      {/* Tab Navigation */}
      <div className="border-b border-border mb-6">
        <nav className="flex space-x-8 overflow-x-auto">
          {([
            { key: 'overview' as Tab, label: 'Overview' },
            { key: 'listings' as Tab, label: 'My Listings' },
            { key: 'sales' as Tab, label: 'Sales History' },
            { key: 'profile' as Tab, label: 'Seller Profile' },
          ]).map(({ key, label }) => (
            <button
              key={key}
              onClick={() => setActiveTab(key)}
              className={cn(
                "py-2 px-1 border-b-2 font-medium text-sm whitespace-nowrap transition-colors",
                activeTab === key
                  ? "border-action text-action"
                  : "border-transparent text-secondary hover:text-primary hover:border-gray-300"
              )}
            >
              {label}
            </button>
          ))}
        </nav>
      </div>

      {/* Tab Content */}
      {activeTab === 'overview' && (
        <div className="space-y-6">
          {/* Trust Tier Progress */}
          {trustData?.tier_progress && (
            <TierProgressCard progress={trustData.tier_progress} />
          )}

          {/* Recent Activity */}
          <div className="bg-card rounded-lg border border-border">
            <div className="p-6 border-b border-border">
              <h3 className="text-lg font-semibold text-primary">Recent Activity</h3>
            </div>
            <div className="p-6">
              {dashboard.recent_activity.length === 0 ? (
                <div className="text-center py-8">
                  <svg className="w-10 h-10 text-gray-400 mx-auto mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                  <p className="text-secondary">No recent activity yet. List your first card to get started!</p>
                </div>
              ) : (
                <div className="space-y-4">
                  {dashboard.recent_activity.map((activity, index) => (
                    <div key={index} className="flex items-center justify-between py-2">
                      <div className="flex items-center gap-3">
                        <div className="w-2 h-2 rounded-full bg-green-500" />
                        <div>
                          <p className="font-medium text-primary">{activity.title}</p>
                          <p className="text-sm text-secondary">{activity.description}</p>
                        </div>
                      </div>
                      <div className="text-right flex-shrink-0">
                        <p className="font-medium text-primary">
                          {formatAmount(activity.amount / 100, 'USD')}
                        </p>
                        <p className="text-sm text-secondary">
                          {formatRelativeTime(activity.created_at)}
                        </p>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Quick Actions */}
          <div className="bg-card rounded-lg border border-border p-6">
            <h3 className="text-lg font-semibold text-primary mb-4">Quick Actions</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
              <Link
                href="/sell/list-card"
                className="flex items-center gap-3 p-4 bg-component rounded-lg hover:bg-component-hover transition-colors"
              >
                <div className="w-10 h-10 bg-green-100 dark:bg-green-900/20 rounded-lg flex items-center justify-center">
                  <svg className="w-5 h-5 text-green-600 dark:text-green-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                  </svg>
                </div>
                <span className="font-medium text-primary">List Card</span>
              </Link>
              <button
                onClick={() => setActiveTab('listings')}
                className="flex items-center gap-3 p-4 bg-component rounded-lg hover:bg-component-hover transition-colors"
              >
                <div className="w-10 h-10 bg-blue-100 dark:bg-blue-900/20 rounded-lg flex items-center justify-center">
                  <svg className="w-5 h-5 text-blue-600 dark:text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" />
                  </svg>
                </div>
                <span className="font-medium text-primary">My Listings</span>
              </button>
              <button
                onClick={() => setActiveTab('sales')}
                className="flex items-center gap-3 p-4 bg-component rounded-lg hover:bg-component-hover transition-colors"
              >
                <div className="w-10 h-10 bg-yellow-100 dark:bg-yellow-900/20 rounded-lg flex items-center justify-center">
                  <svg className="w-5 h-5 text-yellow-600 dark:text-yellow-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                </div>
                <span className="font-medium text-primary">Sales History</span>
              </button>
              <Link
                href="/sell/reputation"
                className="flex items-center gap-3 p-4 bg-component rounded-lg hover:bg-component-hover transition-colors"
              >
                <div className="w-10 h-10 bg-indigo-100 dark:bg-indigo-900/20 rounded-lg flex items-center justify-center">
                  <svg className="w-5 h-5 text-indigo-600 dark:text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                  </svg>
                </div>
                <span className="font-medium text-primary">Reputation</span>
              </Link>
              <Link
                href="/sell/payouts"
                className="flex items-center gap-3 p-4 bg-component rounded-lg hover:bg-component-hover transition-colors"
              >
                <div className="w-10 h-10 bg-emerald-100 dark:bg-emerald-900/20 rounded-lg flex items-center justify-center">
                  <svg className="w-5 h-5 text-emerald-600 dark:text-emerald-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z" />
                  </svg>
                </div>
                <span className="font-medium text-primary">Payouts</span>
              </Link>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'listings' && (
        <div className="space-y-4">
          <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
            <div>
              <h3 className="text-lg font-semibold text-primary">My Listings</h3>
              <p className="text-sm text-secondary">
                {listingsTotal} listing{listingsTotal !== 1 ? 's' : ''} total
              </p>
            </div>
            <div className="flex items-center gap-2">
              <select
                value={listingFilter}
                onChange={(e) => handleListingFilterChange(e.target.value)}
                className="px-3 py-2 border border-border rounded-md bg-background text-primary"
              >
                <option value="all">All Status</option>
                <option value="published">Active</option>
                <option value="draft">Paused</option>
              </select>
              <Link
                href="/sell/list-card"
                className="px-4 py-2 bg-action text-white rounded-md hover:bg-action-hover transition-colors"
              >
                Add Listing
              </Link>
            </div>
          </div>

          {listingsLoading ? (
            <div className="space-y-4">
              {[...Array(3)].map((_, i) => (
                <div key={i} className="h-24 bg-gray-200 dark:bg-gray-700 rounded-lg animate-pulse" />
              ))}
            </div>
          ) : listings.length === 0 ? (
            <div className="bg-card rounded-lg border border-border p-8 text-center">
              <svg className="w-12 h-12 text-gray-400 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" />
              </svg>
              <p className="text-secondary mb-4">No listings found</p>
              <Link
                href="/sell/list-card"
                className="inline-flex items-center gap-2 px-4 py-2 bg-action text-white rounded-lg hover:bg-action-hover transition-colors"
              >
                List Your First Card
              </Link>
            </div>
          ) : (
            <>
              <div className="rounded-lg border border-border overflow-hidden">
                <table className="w-full text-sm">
                  <thead className="sticky top-0 z-10 bg-bg-surface-1">
                    <tr className="border-b border-border">
                      <th className="text-left px-3 py-2 font-medium text-secondary w-12">
                        <span className="sr-only">Thumbnail</span>
                      </th>
                      <th className="text-left px-3 py-2 font-medium text-secondary">Card</th>
                      <th className="text-left px-3 py-2 font-medium text-secondary hidden sm:table-cell">Listed</th>
                      <th className="text-right px-3 py-2 font-medium text-secondary">Price</th>
                      <th className="text-center px-3 py-2 font-medium text-secondary">Status</th>
                      <th className="text-right px-3 py-2 font-medium text-secondary">Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {listings.map((listing, index) => (
                      <tr
                        key={listing.id}
                        className={cn(
                          "density-adaptive-row border-b border-border last:border-0 transition-colors",
                          index % 2 === 0 ? "bg-bg-surface-2" : "bg-bg-surface-1"
                        )}
                      >
                        <td className="px-3">
                          <div className="w-8 card-aspect flex-shrink-0 rounded overflow-hidden" style={{ width: '2rem' }}>
                            {listing.thumbnail ? (
                              <Image
                                src={listing.thumbnail}
                                alt={listing.title}
                                width={32}
                                height={45}
                                className="w-full h-full object-cover"
                              />
                            ) : (
                              <div className="w-full h-full bg-muted rounded flex items-center justify-center">
                                <svg className="w-3 h-3 text-muted-foreground" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" />
                                </svg>
                              </div>
                            )}
                          </div>
                        </td>
                        <td className="px-3">
                          <p className="font-medium text-foreground truncate max-w-[200px]">{listing.title}</p>
                          {listing.variants.length > 0 && listing.variants[0].sku && (
                            <p className="text-xs text-muted-foreground">{listing.variants[0].sku}</p>
                          )}
                        </td>
                        <td className="px-3 text-muted-foreground hidden sm:table-cell whitespace-nowrap">
                          {new Date(listing.created_at).toLocaleDateString()}
                        </td>
                        <td className="px-3 text-right font-medium text-foreground whitespace-nowrap">
                          {listing.variants.length > 0
                            ? formatAmount(listing.variants[0].price / 100, listing.variants[0].currency_code)
                            : '—'}
                        </td>
                        <td className="px-3 text-center">
                          <div className={cn(
                            "inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium",
                            getListingStatusColor(listing.status)
                          )}>
                            <div className={cn(
                              "w-1.5 h-1.5 rounded-full",
                              listing.status === 'published' ? 'bg-green-500 animate-pulse' : 'bg-yellow-500'
                            )} />
                            {listing.status === 'published' ? 'Active' : 'Paused'}
                          </div>
                        </td>
                        <td className="px-3">
                          <div className="flex items-center justify-end gap-1">
                            <button
                              onClick={() => handleToggleListing(listing)}
                              disabled={actionLoading === listing.id}
                              className="p-1.5 hover:bg-accent rounded text-muted-foreground hover:text-foreground disabled:opacity-50"
                              aria-label={listing.status === 'published' ? 'Pause listing' : 'Activate listing'}
                            >
                              {listing.status === 'published' ? (
                                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 9v6m4-6v6m7-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                                </svg>
                              ) : (
                                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                                </svg>
                              )}
                            </button>
                            <button
                              onClick={() => handleDeleteListing(listing)}
                              disabled={actionLoading === listing.id}
                              className="p-1.5 hover:bg-destructive/10 rounded text-muted-foreground hover:text-destructive disabled:opacity-50"
                              aria-label="Delete listing"
                            >
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                              </svg>
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
              <PaginationControls
                offset={listingOffset}
                total={listingsTotal}
                pageSize={PAGE_SIZE}
                onPageChange={handleListingPage}
              />
            </>
          )}
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <div>
              <h3 className="text-lg font-semibold text-primary">Sales History</h3>
              <p className="text-sm text-secondary">
                {ordersTotal} order{ordersTotal !== 1 ? 's' : ''} total
              </p>
            </div>
            {dashboard.pending_orders > 0 && (
              <span className="px-3 py-1 bg-yellow-100 dark:bg-yellow-900/20 text-yellow-700 dark:text-yellow-300 rounded-full text-sm font-medium">
                {dashboard.pending_orders} pending
              </span>
            )}
          </div>

          {ordersLoading ? (
            <div className="space-y-4">
              {[...Array(3)].map((_, i) => (
                <div key={i} className="h-20 bg-gray-200 dark:bg-gray-700 rounded-lg animate-pulse" />
              ))}
            </div>
          ) : orders.length === 0 ? (
            <div className="bg-card rounded-lg border border-border p-8 text-center">
              <svg className="w-12 h-12 text-gray-400 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
              </svg>
              <p className="text-secondary">No sales yet. Once a buyer purchases one of your listings, it will appear here.</p>
            </div>
          ) : (
            <>
              <div className="bg-card rounded-lg border border-border divide-y divide-border">
                {orders.map((order) => (
                  <div key={order.id} className="p-4">
                    <div className="flex items-center justify-between mb-2">
                      <div className="flex items-center gap-3">
                        <span className="font-semibold text-primary">
                          Order #{order.display_id}
                        </span>
                        <span className={cn(
                          "px-2 py-0.5 rounded-full text-xs font-medium",
                          order.status === 'completed' ? 'bg-green-100 text-green-700 dark:bg-green-900/20 dark:text-green-300' :
                          order.status === 'pending' ? 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/20 dark:text-yellow-300' :
                          'bg-gray-100 text-gray-700 dark:bg-gray-700 dark:text-gray-300'
                        )}>
                          {order.status}
                        </span>
                      </div>
                      <span className="font-bold text-primary">
                        {formatAmount(order.total / 100, order.currency_code)}
                      </span>
                    </div>
                    <div className="text-sm text-secondary">
                      {order.items.map((item, i) => (
                        <span key={i}>
                          {i > 0 && ', '}
                          {item.title} x{item.quantity}
                        </span>
                      ))}
                    </div>
                    <p className="text-xs text-secondary mt-1">
                      {new Date(order.created_at).toLocaleDateString()} at{' '}
                      {new Date(order.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </p>
                  </div>
                ))}
              </div>
              <PaginationControls
                offset={orderOffset}
                total={ordersTotal}
                pageSize={PAGE_SIZE}
                onPageChange={handleOrderPage}
              />
            </>
          )}
        </div>
      )}

      {activeTab === 'profile' && (
        <div className="space-y-6">
          <VerificationStatus trustLevel={trustLevel} customer={customer} />

          {/* Seller Info */}
          <div className="bg-card rounded-lg border border-border p-6">
            <h3 className="text-lg font-semibold text-primary mb-4">Seller Information</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <p className="text-sm text-secondary">Store Name</p>
                <p className="font-medium text-primary">{dashboard.seller_name || 'Not set'}</p>
              </div>
              {trustData && (
                <>
                  <div>
                    <p className="text-sm text-secondary">Trust Score</p>
                    <p className="font-medium text-primary">{trustData.trust_score}</p>
                  </div>
                  <div>
                    <p className="text-sm text-secondary">Seller Tier</p>
                    <p className="font-medium text-primary capitalize">{trustData.seller_tier}</p>
                  </div>
                  <div>
                    <p className="text-sm text-secondary">Active Since</p>
                    <p className="font-medium text-primary">
                      {trustData.months_active} month{trustData.months_active !== 1 ? 's' : ''}
                    </p>
                  </div>
                </>
              )}
            </div>
          </div>

          {/* Recent Reviews */}
          {trustData && trustData.recent_reviews.length > 0 && (
            <div className="bg-card rounded-lg border border-border">
              <div className="p-6 border-b border-border">
                <h3 className="text-lg font-semibold text-primary">Recent Reviews</h3>
              </div>
              <div className="divide-y divide-border">
                {trustData.recent_reviews.map((review) => (
                  <div key={review.id} className="p-4">
                    <div className="flex items-center gap-2 mb-1">
                      <div className="flex">
                        {[...Array(5)].map((_, i) => (
                          <svg
                            key={i}
                            className={cn("w-4 h-4", i < review.rating ? "text-yellow-400" : "text-gray-300")}
                            fill="currentColor"
                            viewBox="0 0 20 20"
                          >
                            <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                          </svg>
                        ))}
                      </div>
                      <span className="text-xs text-secondary">
                        {formatRelativeTime(review.created_at)}
                      </span>
                    </div>
                    {review.comment && (
                      <p className="text-sm text-primary">{review.comment}</p>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      <AlertDialog open={!!listingToDelete} onOpenChange={(open) => { if (!open) setListingToDelete(null) }}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete listing?</AlertDialogTitle>
            <AlertDialogDescription>
              {listingToDelete && <>Delete &ldquo;{listingToDelete.title}&rdquo;? This cannot be undone.</>}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleDeleteConfirmed}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  )
}

// --- Sub-components ---

function TierBadge({ tier }: { tier: string }) {
  const colors = TIER_COLORS[tier.toLowerCase()] ?? TIER_COLORS.bronze
  return (
    <span className={cn("px-2 py-0.5 rounded-full text-xs font-semibold capitalize", colors.bg, colors.text)}>
      {tier}
    </span>
  )
}

function TierProgressCard({ progress }: { progress: TierProgress }) {
  const colors = TIER_COLORS[progress.current_tier.toLowerCase()] ?? TIER_COLORS.bronze
  return (
    <div className="bg-card rounded-lg border border-border p-6">
      <div className="flex items-center justify-between mb-3">
        <div>
          <h3 className="text-lg font-semibold text-primary">Trust Tier</h3>
          <p className="text-sm text-secondary">
            Score: {progress.current_score}
            {progress.next_tier && ` / ${progress.next_tier_threshold}`}
          </p>
        </div>
        <TierBadge tier={progress.current_tier} />
      </div>
      {progress.next_tier ? (
        <>
          <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-3 mb-2">
            <div
              className={cn("h-3 rounded-full transition-all duration-500", colors.bar)}
              style={{ width: `${progress.progress_percentage}%` }}
            />
          </div>
          <p className="text-xs text-secondary">
            {progress.progress_percentage}% to <span className="capitalize font-medium">{progress.next_tier}</span>
          </p>
        </>
      ) : (
        <p className="text-sm text-secondary">You&apos;ve reached the highest tier!</p>
      )}
    </div>
  )
}

