          </svg>
        </div>
      </div>
    </div>
  )
}

function PaginationControls({
  offset,
  total,
  pageSize,
  onPageChange,
}: {
  offset: number
  total: number
  pageSize: number
  onPageChange: (offset: number) => void
}) {
  if (total <= pageSize) return null
  const currentPage = Math.floor(offset / pageSize) + 1
  const totalPages = Math.ceil(total / pageSize)

  return (
    <div className="flex items-center justify-between pt-4">
      <p className="text-sm text-secondary">
        Showing {offset + 1}-{Math.min(offset + pageSize, total)} of {total}
      </p>
      <div className="flex items-center gap-2">
        <button
          onClick={() => onPageChange(Math.max(0, offset - pageSize))}
          disabled={offset === 0}
          className="px-3 py-1.5 text-sm border border-border rounded-md hover:bg-component-hover disabled:opacity-50 disabled:cursor-not-allowed"
        >
          Previous
        </button>
        <span className="text-sm text-secondary">
          {currentPage} / {totalPages}
        </span>
        <button
          onClick={() => onPageChange(offset + pageSize)}
          disabled={offset + pageSize >= total}
          className="px-3 py-1.5 text-sm border border-border rounded-md hover:bg-component-hover disabled:opacity-50 disabled:cursor-not-allowed"
        >
          Next
        </button>
      </div>
    </div>
  )
}

// --- Helpers ---

function formatRelativeTime(dateString: string): string {
  const date = new Date(dateString)
  const now = new Date()
  const diffMs = now.getTime() - date.getTime()
  const diffMins = Math.floor(diffMs / 60000)
  const diffHours = Math.floor(diffMs / 3600000)
  const diffDays = Math.floor(diffMs / 86400000)

  if (diffMins < 1) return 'just now'
  if (diffMins < 60) return `${diffMins}m ago`
  if (diffHours < 24) return `${diffHours}h ago`
  if (diffDays < 7) return `${diffDays}d ago`
  return date.toLocaleDateString()
}

"use client"

import { useState, useEffect, useCallback } from 'react'
import Link from 'next/link'
import {
  getPayoutAccount,
  getFinancialSummary,
  type PayoutAccount,
  type FinancialSummary
} from '@/lib/data/seller-payouts'
import { PayoutSetupBanner } from './PayoutSetupBanner'
import { BalanceCards } from './BalanceCards'
import { PayoutHistory } from './PayoutHistory'

export function PayoutDashboard() {
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [payoutAccount, setPayoutAccount] = useState<PayoutAccount | null>(null)
  const [summary, setSummary] = useState<FinancialSummary | null>(null)

  const loadData = useCallback(async () => {
    try {
      setLoading(true)
      setError(null)

      const [accountResult, summaryResult] = await Promise.allSettled([
        getPayoutAccount(),
        getFinancialSummary()
      ])

      if (accountResult.status === 'fulfilled') {
        setPayoutAccount(accountResult.value)
      }

      if (summaryResult.status === 'fulfilled' && summaryResult.value) {
        setSummary(summaryResult.value)
      } else {
        setError('Unable to load financial data. Please try again.')
      }
    } catch {
      setError('Unable to load payout data. Please try again.')
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    loadData()
  }, [loadData])

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="space-y-6">
          <div className="h-8 w-48 bg-muted rounded animate-pulse" />
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            {Array.from({ length: 4 }).map((_, i) => (
              <div
                key={i}
                className="h-24 bg-card border border-border rounded-lg animate-pulse"
              />
            ))}
          </div>
          <div className="h-64 bg-card border border-border rounded-lg animate-pulse" />
        </div>
      </div>
    )
  }

  if (error && !summary) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="bg-card rounded-lg border border-border p-8 text-center">
          <svg
            className="w-12 h-12 text-red-400 mx-auto mb-4"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4c-.77-.833-1.964-.833-2.732 0L4.082 16.5c-.77.833.192 2.5 1.732 2.5z"
            />
          </svg>
          <p className="text-secondary mb-4">{error}</p>
          <button
            onClick={loadData}
            className="px-4 py-2 bg-action text-white rounded-lg hover:bg-action-hover transition-colors"
          >
            Try Again
          </button>
        </div>
      </div>
    )
  }

  const isAccountActive = payoutAccount?.status === 'active'

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="space-y-6">
        {/* Header */}
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
          <div>
            <div className="flex items-center gap-2 mb-1">
              <Link
                href="/sell"
                className="text-secondary hover:text-primary text-sm transition-colors"
              >
                Seller Dashboard
              </Link>
              <span className="text-secondary text-sm">/</span>
              <span className="text-primary text-sm font-medium">Payouts</span>
            </div>
            <h1 className="text-2xl font-bold text-primary">Payouts</h1>
          </div>
          <Link
            href="/sell/payouts/settings"
            className="px-4 py-2 text-sm border border-border rounded-lg hover:bg-muted transition-colors text-primary self-start"
          >
            Payout Settings
          </Link>
        </div>

        {/* Stripe Setup Banner */}
        {!isAccountActive && (
          <PayoutSetupBanner
            hasPayoutAccount={!!payoutAccount}
            accountStatus={payoutAccount?.status}
            onSetupComplete={loadData}
          />
        )}

        {/* Balance Cards */}
        {summary && <BalanceCards summary={summary} />}

        {/* Qualification Progress */}
        {summary && !summary.qualification.is_qualified && (
          <div className="bg-card rounded-lg border border-border p-5">
            <h3 className="text-sm font-semibold text-primary mb-3">
              Seller Qualification Progress
            </h3>
            <p className="text-xs text-secondary mb-4">
              Reach these milestones to unlock daily payouts and remove the{' '}
              {summary.reserve_policy.percentage}% reserve hold.
            </p>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <QualificationMeter
                label="Completed Sales"
                current={summary.qualification.sales_count}
                target={summary.qualification.sales_threshold}
              />
              <QualificationMeter
                label="Days on Platform"
                current={summary.qualification.days_on_platform}
                target={summary.qualification.days_threshold}
              />
            </div>
          </div>
        )}

        {/* Payout History */}
        <div>
          <h2 className="text-lg font-semibold text-primary mb-4">
            Payout History
          </h2>
          {isAccountActive ? (
            <PayoutHistory />
          ) : (
            <div className="bg-card rounded-lg border border-border p-8 text-center">
              <p className="text-secondary text-sm">
                Connect your Stripe account to view payout history.
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

function QualificationMeter({
  label,
  current,
  target
}: {
  label: string
  current: number
  target: number
}) {
  const progress = Math.min((current / target) * 100, 100)
  const isComplete = current >= target

  return (
    <div>
      <div className="flex items-center justify-between mb-1">
        <span className="text-xs font-medium text-secondary">{label}</span>
        <span className="text-xs text-secondary">
          {current} / {target}
          {isComplete && (
            <span className="ml-1 text-green-600 dark:text-green-400">
              &#10003;
            </span>
          )}
        </span>
      </div>
      <div className="h-2 bg-muted rounded-full overflow-hidden">
        <div
          className={`h-full rounded-full transition-all ${
            isComplete ? 'bg-green-500' : 'bg-action'
          }`}
          style={{ width: `${progress}%` }}
        />
      </div>
    </div>
  )
}

"use client"

import { useState } from 'react'
import { createPayoutAccount, initiateOnboarding } from '@/lib/data/seller-payouts'

interface PayoutSetupBannerProps {
  hasPayoutAccount: boolean
  accountStatus?: string
  onSetupComplete?: () => void
}

export function PayoutSetupBanner({
  hasPayoutAccount,
  accountStatus,
  onSetupComplete
}: PayoutSetupBannerProps) {
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const handleSetup = async () => {
    try {
      setLoading(true)
      setError(null)

      if (!hasPayoutAccount) {
        const account = await createPayoutAccount()
        if (!account) {
          setError('Failed to create payout account. Please try again.')
          return
        }
      }

      const result = await initiateOnboarding()
      if (!result) {
        setError('Failed to start onboarding. Please try again.')
        return
      }

      // Check if onboarding has a redirect URL in the data
      const onboardingData = result.onboarding?.data
      const onboardingUrl =
        typeof onboardingData === 'object' &&
        onboardingData !== null &&
        'url' in onboardingData &&
        typeof (onboardingData as Record<string, unknown>).url === 'string'
          ? ((onboardingData as Record<string, unknown>).url as string)
          : null

      if (onboardingUrl && onboardingUrl.startsWith('https://')) {
        window.location.href = onboardingUrl
        return
      }

      onSetupComplete?.()
    } catch {
      setError('Something went wrong. Please try again.')
    } finally {
      setLoading(false)
    }
  }

  if (accountStatus === 'active') {
    return null
  }

  const isPending = hasPayoutAccount && accountStatus === 'pending'

  return (
    <div className="bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-blue-950/30 dark:to-indigo-950/30 border border-blue-200 dark:border-blue-800 rounded-lg p-6">
      <div className="flex items-start gap-4">
        <div className="flex-shrink-0">
          <svg
            className="w-8 h-8 text-blue-600 dark:text-blue-400"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z"
            />
          </svg>
        </div>
        <div className="flex-1">
          <h3 className="text-lg font-semibold text-primary mb-1">
            {isPending
              ? 'Complete Your Payout Setup'
              : 'Set Up Payouts to Start Earning'}
          </h3>
          <p className="text-secondary text-sm mb-4">
            {isPending
              ? 'Your Stripe account setup is incomplete. Complete the onboarding process to start receiving payouts.'
              : 'Connect your bank account through Stripe to receive payments from your sales. Setup takes about 5 minutes.'}
          </p>

          {error && (
            <p className="text-red-600 dark:text-red-400 text-sm mb-3">
              {error}
            </p>
          )}

          <button
            onClick={handleSetup}
            disabled={loading}
            className="px-5 py-2.5 bg-action text-white rounded-lg hover:bg-action-hover transition-colors disabled:opacity-50 disabled:cursor-not-allowed text-sm font-medium"
          >
            {loading
              ? 'Setting up...'
              : isPending
                ? 'Continue Setup'
                : 'Connect Stripe Account'}
          </button>
        </div>
      </div>
    </div>
  )
}

"use client"

import { useState, useEffect } from 'react'
import Link from 'next/link'
import { HttpTypes } from '@medusajs/types'
import {
  getPayoutAccount,
  getFinancialSummary,
  updatePayoutSettings,
  type PayoutAccount,
  type FinancialSummary
} from '@/lib/data/seller-payouts'
import { FeeCalculator } from './FeeCalculator'

interface PayoutSettingsPageProps {
  customer: HttpTypes.StoreCustomer
}

export function PayoutSettingsPage({ customer }: PayoutSettingsPageProps) {
  const [loading, setLoading] = useState(true)
  const [payoutAccount, setPayoutAccount] = useState<PayoutAccount | null>(null)
  const [summary, setSummary] = useState<FinancialSummary | null>(null)
  const [schedule, setSchedule] = useState<'weekly' | 'daily'>('weekly')
  const [saving, setSaving] = useState(false)
  const [saveMessage, setSaveMessage] = useState<{
    type: 'success' | 'error'
    text: string
  } | null>(null)

  useEffect(() => {
    loadData()
  }, [])

  const loadData = async () => {
    try {
      setLoading(true)
      const [accountResult, summaryResult] = await Promise.allSettled([
        getPayoutAccount(),
        getFinancialSummary()
      ])

      if (accountResult.status === 'fulfilled' && accountResult.value) {
        setPayoutAccount(accountResult.value)
        const ctx = accountResult.value.context as Record<string, unknown> | null
        if (ctx?.payout_schedule === 'daily') {
          setSchedule('daily')
        }
      }

      if (summaryResult.status === 'fulfilled') {
        setSummary(summaryResult.value)
      }
    } catch {
      // Graceful degradation
    } finally {
      setLoading(false)
    }
  }

  const handleSaveSchedule = async () => {
    try {
      setSaving(true)
      setSaveMessage(null)

      const success = await updatePayoutSettings(schedule)
      if (success) {
        setSaveMessage({ type: 'success', text: 'Payout schedule updated.' })
      } else {
        setSaveMessage({
          type: 'error',
          text: 'Failed to update schedule. You may not be qualified for daily payouts yet.'
        })
      }
    } catch {
      setSaveMessage({ type: 'error', text: 'Something went wrong.' })
    } finally {
      setSaving(false)
    }
  }

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="space-y-6">
          <div className="h-8 w-48 bg-muted rounded animate-pulse" />
          <div className="h-64 bg-card border border-border rounded-lg animate-pulse" />
        </div>
      </div>
    )
  }

  const isQualified = summary?.qualification.is_qualified ?? false

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="max-w-2xl mx-auto space-y-6">
        {/* Header */}
        <div>
          <div className="flex items-center gap-2 mb-1">
            <Link
              href="/sell"
              className="text-secondary hover:text-primary text-sm transition-colors"
            >
              Seller Dashboard
            </Link>
            <span className="text-secondary text-sm">/</span>
            <Link
              href="/sell/payouts"
              className="text-secondary hover:text-primary text-sm transition-colors"
            >
              Payouts
            </Link>
            <span className="text-secondary text-sm">/</span>
            <span className="text-primary text-sm font-medium">Settings</span>
          </div>
          <h1 className="text-2xl font-bold text-primary">Payout Settings</h1>
        </div>

        {/* Payout Schedule */}
        <div className="bg-card rounded-lg border border-border p-5">
          <h3 className="text-sm font-semibold text-primary mb-1">
            Payout Schedule
          </h3>
          <p className="text-xs text-secondary mb-4">
            Choose how often you receive payouts.
            {!isQualified &&
              ' Daily payouts require 30+ sales and 90+ days on the platform.'}
          </p>

          <div className="space-y-3">
            <label className="flex items-center gap-3 cursor-pointer">
              <input
                type="radio"
                name="schedule"
                value="weekly"
                checked={schedule === 'weekly'}
                onChange={() => setSchedule('weekly')}
                className="text-action focus:ring-action"
              />
              <div>
                <span className="text-sm font-medium text-primary">Weekly</span>
                <p className="text-xs text-secondary">
                  Payouts processed every Monday
                </p>
              </div>
            </label>

            <label
              className={`flex items-center gap-3 ${
                isQualified
                  ? 'cursor-pointer'
                  : 'cursor-not-allowed opacity-50'
              }`}
            >
              <input
                type="radio"
                name="schedule"
                value="daily"
                checked={schedule === 'daily'}
                onChange={() => setSchedule('daily')}
                disabled={!isQualified}
                className="text-action focus:ring-action"
              />
              <div>
                <span className="text-sm font-medium text-primary">Daily</span>
                <p className="text-xs text-secondary">
                  Payouts processed every business day
                  {!isQualified && ' (requires qualification)'}
                </p>
              </div>
            </label>
          </div>

          {saveMessage && (
            <p
              className={`text-sm mt-3 ${
                saveMessage.type === 'success'
                  ? 'text-green-600 dark:text-green-400'
                  : 'text-red-600 dark:text-red-400'
              }`}
            >
              {saveMessage.text}
            </p>
          )}

          <button
            onClick={handleSaveSchedule}
            disabled={saving}
            className="mt-4 px-4 py-2 bg-action text-white rounded-lg hover:bg-action-hover transition-colors disabled:opacity-50 text-sm font-medium"
          >
            {saving ? 'Saving...' : 'Save Schedule'}
          </button>
        </div>

        {/* Reserve Policy */}
        {summary?.reserve_policy.active && (
          <div className="bg-amber-50 dark:bg-amber-950/30 border border-amber-200 dark:border-amber-800 rounded-lg p-5">
            <h3 className="text-sm font-semibold text-primary mb-1">
              Reserve Policy
            </h3>
            <p className="text-xs text-secondary">
              As a new seller, {summary.reserve_policy.percentage}% of your
              earnings are held for {summary.reserve_policy.duration_days} days.
              This reserve is released once you reach qualified seller status
              (30+ sales, 90+ days on platform).
            </p>
          </div>
        )}

        {/* Fee Calculator */}
        <FeeCalculator />

        {/* Tax Information */}
        <div className="bg-card rounded-lg border border-border p-5">
          <h3 className="text-sm font-semibold text-primary mb-1">
            Tax Information
          </h3>
          <p className="text-xs text-secondary">
            If your total earnings exceed $600 in a calendar year, Stripe will
            generate a 1099-K form for tax reporting purposes. You can access
            your tax documents through your Stripe Express dashboard.
          </p>
        </div>
      </div>
    </div>
  )
}

"use client"

import { useState, useEffect, useCallback } from 'react'
import { formatAmount } from '@/lib/helpers/money'
import { getPayoutHistory, type PayoutRecord } from '@/lib/data/seller-payouts'

const PAGE_SIZE = 20

export function PayoutHistory() {
  const [payouts, setPayouts] = useState<PayoutRecord[]>([])
  const [total, setTotal] = useState(0)
  const [offset, setOffset] = useState(0)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const loadPayouts = useCallback(async (newOffset = 0) => {
    try {
      setLoading(true)
      setError(null)
      const result = await getPayoutHistory({ limit: PAGE_SIZE, offset: newOffset })
      if (result) {
        setPayouts(result.payouts)
        setTotal(result.count)
        setOffset(newOffset)
      } else {
        setError('Unable to load payout history.')
      }
    } catch {
      setError('Unable to load payout history.')
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    loadPayouts()
  }, [loadPayouts])

  if (loading) {
    return (
      <div className="space-y-3">
        {Array.from({ length: 5 }).map((_, i) => (
          <div
            key={i}
            className="h-12 bg-card border border-border rounded animate-pulse"
          />
        ))}
      </div>
    )
  }

  if (error) {
    return (
      <div className="bg-card rounded-lg border border-border p-8 text-center">
        <p className="text-secondary mb-4">{error}</p>
        <button
          onClick={() => loadPayouts()}
          className="px-4 py-2 bg-action text-white rounded-lg hover:bg-action-hover transition-colors text-sm"
        >
          Try Again
        </button>
      </div>
    )
  }

  if (payouts.length === 0) {
    return (
      <div className="bg-card rounded-lg border border-border p-8 text-center">
        <svg
          className="w-12 h-12 text-secondary/50 mx-auto mb-3"
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth={1.5}
            d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z"
          />
        </svg>
        <p className="text-secondary text-sm">
          No payouts yet. Payouts will appear here once you start receiving
          payments.
        </p>
      </div>
    )
  }

  const totalPages = Math.ceil(total / PAGE_SIZE)
  const currentPage = Math.floor(offset / PAGE_SIZE) + 1

  return (
    <div>
      <div className="bg-card rounded-lg border border-border overflow-hidden">
        <table className="w-full">
          <thead>
            <tr className="bg-muted/50">
              <th className="text-left px-4 py-3 text-xs font-medium text-secondary uppercase tracking-wider">
                Date
              </th>
              <th className="text-left px-4 py-3 text-xs font-medium text-secondary uppercase tracking-wider">
                Amount
              </th>
              <th className="text-left px-4 py-3 text-xs font-medium text-secondary uppercase tracking-wider hidden sm:table-cell">
                ID
              </th>
            </tr>
          </thead>
          <tbody className="divide-y divide-border">
            {payouts.map((payout) => (
              <tr key={payout.id} className="hover:bg-muted/30 transition-colors">
                <td className="px-4 py-3 text-sm text-primary">
                  {new Date(payout.created_at).toLocaleDateString('en-US', {
                    month: 'short',
                    day: 'numeric',
                    year: 'numeric'
                  })}
                </td>
                <td className="px-4 py-3 text-sm font-medium text-primary">
                  {formatAmount(
                    Number(payout.amount) / 100,
                    payout.currency_code.toUpperCase()
                  )}
                </td>
                <td className="px-4 py-3 text-sm text-secondary font-mono hidden sm:table-cell">
                  {payout.id.slice(0, 16)}...
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {totalPages > 1 && (
        <div className="flex items-center justify-between mt-4">
          <p className="text-sm text-secondary">
            Showing {offset + 1}-{Math.min(offset + PAGE_SIZE, total)} of{' '}
            {total}
          </p>
          <div className="flex gap-2">
            <button
              onClick={() => loadPayouts(offset - PAGE_SIZE)}
              disabled={offset === 0}
              className="px-3 py-1.5 text-sm border border-border rounded hover:bg-muted transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Previous
            </button>
            <button
              onClick={() => loadPayouts(offset + PAGE_SIZE)}
              disabled={currentPage >= totalPages}
              className="px-3 py-1.5 text-sm border border-border rounded hover:bg-muted transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Next
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import { formatAmount } from '@/lib/helpers/money'
import type { FinancialSummary } from '@/lib/data/seller-payouts'

interface BalanceCardsProps {
  summary: FinancialSummary
}

export function BalanceCards({ summary }: BalanceCardsProps) {
  const currency = summary.currency.toUpperCase()

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
      <BalanceCard
        label="Available Balance"
        amount={summary.available_balance / 100}
        currency={currency}
        variant="highlight"
      />
      <BalanceCard
        label="Pending"
        amount={summary.pending_balance / 100}
        currency={currency}
        subtitle={
          summary.reserve_policy.active
            ? `${summary.reserve_percentage}% reserve held`
            : undefined
        }
      />
      <BalanceCard
        label="Gross Revenue"
        amount={summary.gross_revenue / 100}
        currency={currency}
      />
      <BalanceCard
        label="Lifetime Payouts"
        amount={summary.lifetime_earnings / 100}
        currency={currency}
      />
    </div>
  )
}

function BalanceCard({
  label,
  amount,
  currency,
  subtitle,
  variant
}: {
  label: string
  amount: number
  currency: string
  subtitle?: string
  variant?: 'highlight'
}) {
  return (
    <div
      className={`bg-card rounded-lg border p-5 ${
        variant === 'highlight'
          ? 'border-action/30 bg-action/5'
          : 'border-border'
      }`}
    >
      <p className="text-xs font-medium text-secondary uppercase tracking-wider mb-1">
        {label}
      </p>
      <p className="text-2xl font-bold text-primary">
        {formatAmount(amount, currency)}
      </p>
      {subtitle && (
        <p className="text-xs text-secondary mt-1">{subtitle}</p>
      )}
    </div>
  )
}

